const useAdminTranslation = () => {
  const { lang } = useContext(LanguageContext);
  const t = useCallback((text: string) => {
    if (!text) return "";
    const trimmed = text.trim();
    if (lang === 'vi') return trimmed;
    
    // Check in adminTranslations first
    const adminDict = adminTranslations[lang] || adminTranslations['en'] || {};
    if (adminDict[trimmed]) {
      return adminDict[trimmed];
    }
    
    // Fallback to general translations
    const generalDict = translations[lang] || translations['en'] || {};
    if (generalDict[trimmed]) {
      return generalDict[trimmed];
    }
    
    return trimmed;
  }, [lang]);
  return { t, lang };
};

interface LangContextType {
  lang: string;
  setLang: (l: string) => void;
  artistData?: any;
  setArtistData?: (data: any) => void;
  landingConfig?: any;
  setLandingConfig?: (data: any) => void;
}
const LanguageContext = createContext<LangContextType>({ lang: 'vi', setLang: () => {} });

